  if (!response.ok) throw new Error("request failed");
  return response.json();
}

const byOperator6Id = new Map();
for (const item of operator6s) {
  if (item.enabled) byOperator6Id.set(item.id, item);
}

export function createOrganization6Store(initialItems = []) {
  const listeners = new Set();
  let items = [...initialItems];
  return { getSnapshot: () => items, subscribe: (fn) => listeners.add(fn) };
}

document.querySelectorAll("[data-package6]").forEach((node) => {
  node.addEventListener("click", () => {
    node.toggleAttribute("data-selected");
  });
});

const sortedPolicy6s = [...policy6s].sort((left, right) => {
  return left.createdAt.localeCompare(right.createdAt);
});

import { readFile } from "node:fs/promises";

export async function loadPreset6Config(path) {
  const raw = await readFile(path, "utf8");
  const config = JSON.parse(raw);
  return { ...config, loaded: true };
}

